import{_ as e,o as a,c as t,ag as o}from"./chunks/framework.eQLvDOR_.js";const p=JSON.parse('{"title":"wiki-automated-generation","description":"","frontmatter":{"title":"wiki-automated-generation","concept":"Wiki Automated Generation","concept_id":"wiki-automated-generation","aliases":["Wiki-Compilation-Logic","自动化 Wiki"],"sources":["02_Library/Claude_Code_Skills/[Claude_Code_Skills] wiki-gen-skill.md"],"related_concepts":["[[llm-augmented-wiki]]","[[skill-lifecycle]]"],"created_at":"2026-04-07","last_compiled":"2026-04-07"},"headers":[],"relativePath":"wiki/concepts/wiki-automated-generation.md","filePath":"wiki/concepts/wiki-automated-generation.md","lastUpdated":null}'),l={name:"wiki/concepts/wiki-automated-generation.md"};function s(n,i,r,d,c,k){return a(),t("div",null,[...i[0]||(i[0]=[o('<h1 id="wiki-automated-generation-wiki-自动化生成" tabindex="-1">Wiki Automated Generation (Wiki 自动化生成) <a class="header-anchor" href="#wiki-automated-generation-wiki-自动化生成" aria-label="Permalink to &quot;Wiki Automated Generation (Wiki 自动化生成)&quot;">​</a></h1><h2 id="逻辑链路" tabindex="-1">逻辑链路 <a class="header-anchor" href="#逻辑链路" aria-label="Permalink to &quot;逻辑链路&quot;">​</a></h2><p>通过 Agent Skill 实现“剪藏库 (Library) -&gt; 知识库 (Wiki)”的自动化蒸馏。</p><h2 id="核心流程" tabindex="-1">核心流程 <a class="header-anchor" href="#核心流程" aria-label="Permalink to &quot;核心流程&quot;">​</a></h2><ol><li><strong>内容扫描</strong>：使用 <code>grep</code> 或 <code>list_dir</code> 寻找 <code>compiled: false</code> 的文章。</li><li><strong>意图蒸馏</strong>：LLM 阅读全文，提取核心概念 (Concepts) 和模式 (Patterns)，而非全量摘要。</li><li><strong>元数据对齐</strong>：自动生成符合 Wiki 规范的 YAML Frontmatter（包括 <code>concept_id</code>, <code>aliases</code> 等）。</li><li><strong>冲突检测</strong>：检查新概念是否与现有 Wiki 页面重合，并决定是 <strong>[New]</strong> 还是 <strong>[Merge]</strong>。</li><li><strong>双向索引更新</strong>： <ul><li>将新路径加入 <code>03_Wiki/_index.md</code>。</li><li>将源文章标记为 <code>✅</code> 并移动分类。</li><li>在 <code>_log.md</code> 记录操作历史。</li></ul></li></ol><h2 id="关键代码段-sop" tabindex="-1">关键代码段 (SOP) <a class="header-anchor" href="#关键代码段-sop" aria-label="Permalink to &quot;关键代码段 (SOP)&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/compile-wiki</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --file</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Article_Name.md&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --mode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> focus</span></span></code></pre></div><p><em>(逻辑来源于 wiki-gen-skill.md 内部定义的 Workflow)</em></p><hr><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><ul><li><strong>流水线调试</strong>：如果 <code>/compile-wiki</code> 产生幻觉，检查 <code>PROMPT_TEMPLATES</code> 是否过时。2026 年的模型对“深度关系提取”有极强的偏好，应在模板中增加对 <code>related_concepts</code> 的强制要求。</li><li><strong>清理逻辑</strong>：在自动生成后，建议通过 <code>git status</code> 审查变更。如果产生空文件或元数据错误的页面，优先撤销并更新蒸馏 Prompt，而非手动修复单个文件。</li><li><strong>构建触发</strong>：建议将 <code>npm run docs:build</code> 集成为 Git Hook，确保 Wiki 内容与发布站点实时同步。</li></ul><hr><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="/s/webclips/library/Claude_Code_Skills/Claude_Code_Skills - wiki-gen-skill.html">[Claude_Code_Skills] wiki-gen-skill</a></li></ul>',14)])])}const u=e(l,[["render",s]]);export{p as __pageData,u as default};
